insert into public.travels (id, title, preview, description, status, country_id, city_id, date_from, date_to, members, members_exists, travel_type_id, public_id, visible_type, user_id, created_at, updated_at)
values  (6, 'Горные приключения', 'Маршрут включает в себя самые технически сложные участки. Общая протяженность составии около 15 километров. Особая сложность - переправы через водоемы.', null, 1, 7, null, '2025-04-01', '2025-04-06', 15, 0, 2, '2749411214', 2, 5, '2025-03-04 16:52:28 +00:00', '2025-03-04 16:56:29 +00:00'),
        (25, 'Доломиты', 'Описание: "Маршрут по живописным горам Доломитов, включающий технические участки с перепадами высоты до 2000м. Особенности: уникальные скальные образования, альпийские озера и средневековые г', null, 1, 107, null, '2025-04-03', '2025-04-06', null, 0, 1, '645008136', 1, 2, '2025-03-04 17:26:42 +00:00', null),
        (26, 'Адриатическое побережье', 'Маршрут вдоль Адриатического побережья с живописными видами на море. Особенности: средневековые города, островные переходы и чистые пляжи.', null, 1, 95, null, '2025-03-24', '2025-03-30', null, 0, 1, '3229697649', 1, 34, '2025-03-04 17:27:17 +00:00', null),
        (27, 'Казахстан - Тянь-Шань', 'Маршрут по горам Тянь-Шаня с уникальными ландшафтами и разнообразной флорой. Особенности: высокогорные озера, альпийские луга и древние торговые пути.', null, 1, 122, null, '2025-04-02', '2025-04-06', null, 0, 1, '1392957620', 2, 88, '2025-03-04 17:27:49 +00:00', null),
        (21, 'Grand Paradiso', 'A 4,061m peak offering stunning views of Mont Blanc. The climb involves glacier travel and moderate ice climbing, making it an excellent introduction to high-altitude mountaineering.', null, 1, 107, null, '2025-05-18', '2025-05-25', 12, 0, 5, '3098322009', 2, 46, '2025-03-04 17:19:21 +00:00', '2025-03-04 17:28:42 +00:00'),
        (17, 'Mont Blanc Classic Route', 'The most popular route to climb Mont Blanc, starting from Les Houches. The first day involves taking the Bellevue cable car and TMB train to Nid d''Aigle (2,372m), followed by a 3-hour hike to Tete Rousse hut. The second day requires serious mountaineering experience, crossing the Gouter couloir and climbing the Gouter spur to reach the Gouter hut (', null, 1, 72, null, '2025-03-20', '2025-03-23', 6, 3, 5, '3704736828', 1, 2, '2025-03-04 17:16:47 +00:00', '2025-03-04 18:29:57 +00:00'),
        (19, 'Mont Blanc Grand Mulets Route', 'A historic spring route (April-June) that combines skiing and mountaineering. Starting from Plan de l''Aiguille, traverse to the Jonction and enter the Bossons glacier. The first day ends at the Grand Mulets hut, while the second day involves an early start to ascend the north ridge of the Dome du Gouter and join the normal route to the summit.', null, 1, 72, null, '2025-04-05', '2025-04-11', 2, 1, 5, '2061043488', 1, 2, '2025-03-04 17:17:48 +00:00', '2025-03-04 18:29:57 +00:00'),
        (11, 'Spływ Kajakowy po Krutyni', 'Jedna z najbardziej znanych tras kajakowych w Polsce. Szlak prowadzi przez malownicze tereny, gdzie można spotkać rzadkie czarne łabędzie, bakłanów i żurawie. Wzdłuż trasy znajdują się liczne przystanie i miejsca na posiłki, gdzie można skosztować lokalnej ryby.', null, 1, 176, null, '2025-03-07', '2025-03-09', 6, 6, 4, '77117886', 2, 29, '2025-03-04 17:05:23 +00:00', '2025-03-04 18:29:57 +00:00'),
        (7, 'Лесные приключения', 'Идея похода возникла спонтанно - решили исследовать Сочинское побережье. Маршрут включает в себя менее известные тропы. Общая протяженность составит', null, 1, 76, null, '2025-06-04', '2025-06-08', 6, 2, 3, '3426879519', 2, 27, '2025-03-04 16:53:54 +00:00', '2025-03-04 18:29:57 +00:00'),
        (14, 'Spływ Biebrząński', 'Wyprawa przez największe bagna Polski. Trasa prowadzi przez tereny Parku Narodowego, gdzie można spotkać łosie, bobry i inne rzadkie gatunki zwierząt. Szczególnie bogata fauna ptaków przyciąga miłośników ornitologii.', null, 1, 176, null, '2025-03-08', '2025-03-09', 8, 3, 4, '331941826', 2, 33, '2025-03-04 17:06:46 +00:00', '2025-03-04 18:29:57 +00:00'),
        (10, 'Велопоход с пешими этапами', 'Комбинированный маршрут по лесным тропам и асфальту. Чередование велосипедных этапов с пешими переходами через живописные места.', null, 1, 176, null, '2025-03-25', '2025-03-30', 2, 1, 1, '1657388740', 2, 64, '2025-03-04 16:59:30 +00:00', '2025-03-04 18:29:57 +00:00'),
        (20, 'Switzerland - Matterhorn', 'One of the most iconic peaks in the Alps, requiring excellent physical fitness and technical experience. The route involves steep rock and ice climbing, exposed ridges, and careful navigation of serac zones.', null, 1, 42, null, '2025-04-03', '2025-04-06', 55, 1, 5, '2703774151', 2, 2, '2025-03-04 17:18:52 +00:00', '2025-03-04 18:29:57 +00:00'),
        (12, 'Przygoda na Czarna Hańcza', 'Wyjątkowa podróż wzdłuż rzeki Czarna Hańcza i Kanału Augustowskiego. Trasa prowadzi przez wysokie drzewa zwisające nad wodą, a podczas spływu można obserwować różnorodne ptactwo wodne. Szczególnie interesujący jest przepływ przez historyczne śluzy.', null, 1, 176, null, '2025-03-15', '2025-03-16', 9, 2, 4, '1080313692', 2, 2, '2025-03-04 17:05:48 +00:00', '2025-03-04 18:29:57 +00:00'),
        (23, 'Кавказский переход', '434-километровый маршрут через Малый Кавказ, включающий гравийные дороги и тропы для скота.', null, 1, 7, null, '2025-03-10', '2025-03-16', 6, 1, 1, '2839085909', 2, 2, '2025-03-04 17:25:02 +00:00', '2025-03-04 18:29:57 +00:00'),
        (22, 'Monte Rosa', 'At 4,563m, Monte Rosa is the highest peak entirely in Switzerland. The climb requires advanced glacier travel skills and involves multiple days of high-altitude mountaineering.', null, 1, 42, null, '2025-03-13', '2025-03-16', 3, 3, 5, '2281383995', 1, 65, '2025-03-04 17:19:49 +00:00', '2025-03-04 18:29:57 +00:00'),
        (15, 'Przygoda na Drawie', 'Malownicza trasa prowadząca przez Kotlinę Pięciu Jezior i Drawski Park Krajobrazowy. Szlak wiedzie przez rezerwaty dębów i tereny chronionej przyrody. Idealny dla miłośników spokojnego płynięcia i obserwacji przyrody.', null, 1, 176, null, '2025-04-02', '2025-04-06', 9, 1, 4, '4146681239', 2, 49, '2025-03-04 17:07:23 +00:00', '2025-03-04 18:29:57 +00:00'),
        (8, 'Фотографическое путешествие по водопадам', 'Поиск самых скрытых и впечатляющих водопадов в лесу. Каждый участник получит задание запечатлеть уникальные кадры на рассвете и закате. Вечера посвящены обработке фотографий и обмену опытом.', null, 1, 176, null, '2025-03-05', '2025-03-09', 6, 5, 3, '1330956847', 2, 26, '2025-03-04 16:57:59 +00:00', '2025-03-04 18:29:57 +00:00'),
        (13, 'Ekstremalny Spływ Dunajcem', 'Wycieczka kajakowa wymagająca doświadczenia. Rzeka znana jest ze swojego silnego prądu i wartkich wód. Najlepiej wybrać się z doświadczonym przewodnikiem i odpowiednim sprzętem. Latem nurt jest nieco spokojniejszy niż w zimie', null, 1, 176, null, '2025-03-27', '2025-03-30', 8, 0, 4, '4261132049', 2, 84, '2025-03-04 17:06:17 +00:00', '2025-03-04 17:28:42 +00:00'),
        (9, 'Сплав по горным рекам', 'Сплав по бурной горной реке с порогами разной категории сложности. Командная работа и обучение технике управления судном в различных условиях.', null, 1, 222, null, '2025-06-01', '2025-06-04', 4, 0, 4, '3865183645', 2, 69, '2025-03-04 16:58:47 +00:00', '2025-03-04 17:28:42 +00:00'),
        (16, 'Ekstremalny Spływ Białki Tatrzańskiej', 'Jedna z najczystszych rzek Tatr, ale również jedna z najtrudniejszych do pokonania. Silny nurt i wartkie wody wymagają dużego doświadczenia. Zalecana tylko dla zaawansowanych kajakarzy z własnym sprzętem.', null, 1, 176, null, '2025-04-05', '2025-04-06', 3, 0, 4, '3539588690', 1, 57, '2025-03-04 17:07:55 +00:00', '2025-03-04 17:28:42 +00:00'),
        (4, 'По Байкалу 7-10 дней', 'Нужен велосипед с шипованными покрышками  ( теплый спальнк зимний  или 2 обычных ) еда на этот период .
Для получения возможности подписаться на Покатушка необходимо ввести логин и пароль.', null, 1, 188, null, '2025-04-04', '2025-04-06', 3, 3, 3, '241942954', 2, 2, '2025-03-03 10:36:15 +00:00', '2025-03-04 18:29:57 +00:00'),
        (3, 'Подышать воздухом', 'Ничего более красивого в природе Беларуси в конце 24 года вы уже не увидете. Несмотря на то, что воды мало, болото Острова Дулебы продолжает радовать буйством красок, начиная от великолепного зеленого мха и заканчивая спелой клюквой.', null, 1, 35, null, '2025-02-25', '2025-02-27', 23, 18, 3, '728993538', 2, 2, '2025-03-03 10:35:25 +00:00', '2025-03-04 18:29:57 +00:00'),
        (2, 'Болотные приключения. Дулебы', 'ИИдейно все просто - Идем искать приключения по болоту Острова Дулебы. Болото уже хожено-перехожено. Поэтому целенаправленно идем по самым технически интересным участкам с северной стороны. Общий метраж небольшой, и это с учетом дорог. Ставка делается на сложность и интересность маршрута, чтобы устать от приключений, а не от', null, 1, 35, null, '2025-03-10', '2025-03-13', 8, 8, 3, '632172919', 2, 2, '2025-03-03 10:34:15 +00:00', '2025-03-04 18:29:57 +00:00'),
        (24, 'Тбилиси-Ереван', '173-километровый маршрут через горы, включающий сложный подъём на перевал высотой 2,157м. Особенности: живописные виды на горы, исторические монастыри и традиционные грузинские деревни.', null, 1, 76, null, '2025-03-24', '2025-03-30', 9, 1, 1, '2136922463', 2, 30, '2025-03-04 17:25:38 +00:00', '2025-03-04 18:29:57 +00:00'),
        (18, 'Mont Blanc Cosmique Route', 'A more challenging and less crowded route starting from the Aiguille du Midi cable car (3,842m). The first day involves descending a sharp snow ridge to reach the Cosmique hut (3,613m). The second day begins at 2-3 AM with steep and exposed slopes on Mont Blanc du Tacul, followed by a traverse of Mont Maudit with technical ice climbing sections.', null, 1, 72, null, '2025-03-26', '2025-03-30', 10, 3, 5, '3896925984', 1, 2, '2025-03-04 17:17:17 +00:00', '2025-03-04 18:29:57 +00:00'),
        (5, 'Тур дю Монблан', 'Многодневный поход вокруг самой высокой вершины Альп с захватывающими видами на Монблан', null, 1, 72, null, '2025-04-16', '2025-04-20', 5, 2, 2, '610351077', 2, 2, '2025-03-03 10:40:12 +00:00', '2025-03-04 18:29:57 +00:00');